
import { Component, Prop, h, Event, EventEmitter } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

@Component({
  tag: 'wdpr-pagination-item',
  shadow: true,
})
export class WdprPaginationItem {

  @Prop() page: number | string;
  @Prop() selected: boolean = false;
  @Prop() disabled: boolean = false;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;
  @Event() wdprClick: EventEmitter<void>;

  private _handleClick = (event: MouseEvent) => {
    if (this.disabled) {
      event.preventDefault();
      event.stopImmediatePropagation();

      return;
    }

    if (!this.selected) {
      this.wdprClick.emit();
    }
  };

  render() {
    const baseClasses = "relative inline-flex items-center justify-center rounded-pill border border-solid transition-colors cursor-pointer focus:outline-none focus-visible:outline-037 focus-visible:outline-stroke-actionable-alt-focused focus-visible:outline-solid focus-visible:outline-offset-2 disabled:cursor-not-allowed select-none p-0 w-dimension-500 h-dimension-500";
    const labelClasses = "text-component-small font-component-accent leading-component-medium tracking-default whitespace-nowrap";
    const buttonClasses = customTwMerge(
      baseClasses,
      "text-text-actionable-alt-default border-stroke-actionable-alt-default bg-surface-default",
      "hover:text-text-actionable-alt-hover hover:border-stroke-actionable-alt-hover hover:bg-surface-default",
      "active:text-text-actionable-alt-pressed active:border-stroke-actionable-alt-pressed active:bg-surface-default",
      "disabled:text-text-actionable-alt-disabled disabled:border-stroke-actionable-alt-disabled disabled:bg-surface-disabled",

      // Selected State (overrides)
      "data-[selected=true]:bg-surface-actionable-alt-selected data-[selected=true]:text-text-inverse data-[selected=true]:border-transparent",
      "data-[selected=true]:hover:bg-surface-actionable-alt-hover data-[selected=true]:hover:text-text-inverse",
      "data-[selected=true]:active:bg-surface-actionable-alt-pressed data-[selected=true]:active:text-text-inverse",
      "data-[selected=true]:disabled:bg-surface-actionable-alt-disabled data-[selected=true]:disabled:text-text-actionable-inverse-default"
    );

    return (
      <button
        type="button"
        class={buttonClasses}
        onClick={this._handleClick}
        disabled={this.disabled}
        aria-pressed={this.selected ? 'true' : 'false'}
        data-selected={this.selected ? 'true' : 'false'}
        aria-label={this.a11yLabel}
      >
        <span class={labelClasses}>
          {this.page}
        </span>
      </button>
    );
  }
}
